import './index.css';
import startImage from './assets/startpage.png'; // ← 여기만 파일 이름 반영

function App() {
  return (
    <div className="min-h-screen flex flex-col items-center justify-between bg-gradient-to-b from-white to-blue-50 py-10 px-4">
      {/* 타이틀 */}
      <h1 className="text-2xl md:text-3xl font-bold text-blue-600 mt-8">
        HomeProtect
      </h1>

      {/* 중앙 이미지 */}
      <img
        src={startImage}
        alt="홈 이미지"
        className="max-w-md md:max-w-xl w-full object-contain"
      />

      {/* 시작하기 버튼 */}
      <div className="flex items-center gap-2 mb-12">
        <span className="text-blue-600 text-lg">→</span>
        <button className="bg-blue-600 text-white px-6 py-2 rounded-full hover:bg-blue-700 transition">
          시작하기
        </button>
      </div>
    </div>
  );
}

export default App;
